OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page

//   if(IsProject()==0)    int textMode = 0;

   int textMode = 0;





   int theEnd=0;

   int playNo=0;



   // 0 - kurtyna na dole, 1 - kurtyna na gorze

   int kurtyna = 0;



   LoadGroup("Cursors.grp");

   SetCursor(0);



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   SetTextMode();

//############################################################################

//   SetTimer(5000);

   FadeScreen(1,1000);

}





void OnClosePage(void)

{

	// Add your close page handler code here



}







void SetTextMode()

{

   Transparent_Video_Holder.Stop();

   Text_Holder.HideText(0);

   Text_Holder.StopSynchroText(0);

   theEnd=0;

   playNo=0;



   Transparent_Video_Holder.HideFirsLastVideoFrame(0);





   if( kurtyna )

   {

      Transparent_Video_Holder.Play(13,0);

      Transparent_Video_Holder.HideFirsLastVideoFrame(1);

      return;

   }



   if( textMode )

   {

      Transparent_Video_Holder.Play(1,0);

      Transparent_Video_Holder.HideFirsLastVideoFrame(13);

   }

   else

   {

      Transparent_Video_Holder.Play(0,0);

   }

}







void Transparent_Video_Holder.TheEnd(int videoID)

{

   if( textMode && (videoID!=13) )

   {

      if( videoID==1 )

      {

            playStatus=1;

            kurtyna = 1;

            Sound_Holder.PlayDSound(0);

            Text_Holder.SetTextOffsets(0,0,0);

            Text_Holder.DisableMouse(0);

            Text_Holder.ShowText(0);

      }

      return;

   }



   switch(videoID)

   {

      case 0:

      case 1:

         if( videoID == 1 ) 

            kurtyna = 1;



         playNo++;

         Transparent_Video_Holder.Play(playNo,0);

         Transparent_Video_Holder.HideFirsLastVideoFrame(playNo-1);

         if(videoID==1)

         {

            if(textMode)

               Text_Holder.ShowText(0);

            else

               Text_Holder.HideText(0);

            Text_Holder.SetTextOffsets(0,0,0);

            Text_Holder.PlaySynchroText(0);

         }

         break;

      case 5:

      case 8:

      case 10:

      case 11:

         Transparent_Video_Holder.Play(playNo,0);

         Transparent_Video_Holder.HideFirsLastVideoFrame(playNo-1);

         playNo++;

         break;



      case 13:

         kurtyna = 0;

         Transparent_Video_Holder.ResetVideo(1);

         Transparent_Video_Holder.HideFirsLastVideoFrame(13);

         SetTextMode();



         /*

         if(theEnd)

         {

            FadeScreen(0,1000);

            LoadPage("wyborw.bdf");

         }

         */

         break;

   }

}



void Text_Holder.PlayMark(int textID,int markNo)

{

   if( textMode ) return;



   if(markNo<7)

   {

        Transparent_Video_Holder.Play(playNo,0);

        Transparent_Video_Holder.HideFirsLastVideoFrame(playNo-1);

        playNo++;

   }

}



